   160→}
   161→
   162→impl<S, A: Encode<S>, B: Encode<S>> Encode<S> for (A, B) {
   163→    fn encode(self, w: &mut Writer, s: &mut S) {
   164→        self.0.encode(w, s);
   165→        self.1.encode(w, s);
   166→    }
   167→}
