   185→    fn decode(r: &mut Reader<'a>, s: &mut S) -> Self {
   186→        let len = usize::decode(r, s);
   187→        let xs = &r[..len];
   188→        *r = &r[len..];
   189→        xs
   190→    }
   191→}
