   247→        if let Some(s) = payload.downcast_ref::<&'static str>() {
   248→            return PanicMessage::StaticStr(s);
   249→        }
   250→        if let Ok(s) = payload.downcast::<String>() {
   251→            return PanicMessage::String(*s);
   252→        }
   253→        PanicMessage::Unknown
   254→    }
   255→}
   256→
