   260→            PanicMessage::StaticStr(s) => Box::new(s),
   261→            PanicMessage::String(s) => Box::new(s),
   262→            PanicMessage::Unknown => {
   263→                struct UnknownPanicMessage;
   264→                Box::new(UnknownPanicMessage)
   265→            }
   266→        }
   267→    }
   268→}
